import { useMemo, useState, useRef, useEffect } from "react";
import { Landmark, ChevronDown, Languages, Loader2, RotateCcw, ThumbsUp, ThumbsDown, Share2, MessageSquare } from "lucide-react";
import { useTranslation } from "react-i18next";
import IChingSection from "@/components/IChingSection";
import { useIsMobile } from "@/hooks/use-mobile";
import { useStoryReactions } from "@/hooks/useStoryReactions";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import RestaurantComments from "@/components/RestaurantComments";
import { useComments } from "@/hooks/useComments";
import { useSmartShare } from "@/components/ShareDrawer";

/**
 * Split story into building narrative + I Ching section.
 * 
 * Strategy: Find the pure I Ching citation (e.g. 《易经·革》："..." or "I Ching, Hexagram...")
 * and split there. Transition sentences like "这恰如《易经》中的..." stay with the narrative
 * to preserve sentence flow. Only standalone I Ching paragraphs get separated.
 */

// Patterns that match a STANDALONE I Ching paragraph/section (preceded by sentence-end or newline)
// These capture: (narrative before) + (iching section)
const iChingStandalonePatterns = [
  // Chinese: 《易经·XX》 at start of line or after sentence-ending punctuation
  /([\s\S]*?[。！？\n])\s*(《易经[\s·\-][\s\S]*$)/s,
  // Chinese: newline + 《易经
  /([\s\S]*?)(\n\s*《易经[\s\S]*$)/s,
  // Chinese: double newline before transition words
  /([\s\S]*?)(\n\s*(?:这恰如|恰如|正如|这正如|这如同|如同|犹如|宛如)《易经[\s\S]*$)/s,
  // English: standalone I Ching paragraph after period/newline
  /([\s\S]*?[.\n])\s*((?:I Ching|Book of Changes|Yi Jing)[,\s]*(?:Hexagram|hexagram|quote|says|states|teaches|reminds|"|\()[\s\S]*$)/si,
  // English: newline + transition to I Ching  
  /([\s\S]*?)(\n\s*(?:This echoes|This resonates|As the|This is akin to|This reflects|Much like|Just as)[\s\S]*?(?:I Ching|Book of Changes|Yi Jing)[\s\S]*$)/si,
  // Portuguese
  /([\s\S]*?[.\n])\s*((?:I Ching|Livro das Mutações)[,\s]*(?:hexagrama|diz|ensina|"|\()[\s\S]*$)/si,
  /([\s\S]*?)(\n\s*(?:Isso ecoa|Isso ressoa|Como o|Assim como|Tal como)[\s\S]*?(?:I Ching|Livro das Mutações)[\s\S]*$)/si,
  // Other languages
  /([\s\S]*?[.\n])\s*((?:Yi King|Livre des Mutations)[\s\S]*$)/si,
  /([\s\S]*?[.\n])\s*((?:Libro de los Cambios)[\s\S]*$)/si,
  /([\s\S]*?[.\n])\s*((?:I Ging|Buch der Wandlungen)[\s\S]*$)/si,
  /([\s\S]*?[。.\n])\s*((?:易経)[\s\S]*$)/s,
  /([\s\S]*?[.\n])\s*((?:주역|역경)[\s\S]*$)/s,
  /([\s\S]*?[.\n])\s*((?:И Цзин|Книга Перемен)[\s\S]*$)/si,
  /([\s\S]*?[.\n])\s*((?:Libro dei Mutamenti)[\s\S]*$)/si,
  /([\s\S]*?[.\n])\s*((?:كتاب التغيرات|كتاب التغييرات)[\s\S]*$)/s,
  /([\s\S]*?[.\n])\s*(\(I Ching\)[\s\S]*$)/si,
  /([\s\S]*?[.\n])\s*((?:Hexagram|hexagrama|Hexagramm|hexagramme)\s*\d+[\s\S]*$)/si,
];

// Fallback: inline I Ching mixed into last sentence (less clean split, but still extract)
const iChingInlinePatterns = [
  /(.*?)((?:这恰如|恰如|正如|这正如|这如同|如同|犹如|宛如)《易经[\s\S]*$)/s,
  /(.*?)(《易经[\s\S]*$)/s,
  /(.*?)((?:This echoes|This resonates|As the|This is akin to|This reflects|Much like|Just as)[\s\S]*?(?:I Ching|Book of Changes|Yi Jing)[\s\S]*$)/si,
];

function splitStory(text: string): { main: string; iching: string | null } {
  // First try standalone patterns (clean paragraph break)
  for (const pattern of iChingStandalonePatterns) {
    const match = text.match(pattern);
    if (match && match[1].trim().length > 0 && match[2].trim().length > 0) {
      return { main: match[1].trim(), iching: match[2].trim() };
    }
  }
  // Fallback: inline patterns — keep transition sentence in BOTH main and iching
  // so narrative stays complete while iching section also has context
  for (const pattern of iChingInlinePatterns) {
    const match = text.match(pattern);
    if (match && match[1].trim().length > 0 && match[2].trim().length > 0) {
      // Keep the full text as narrative (no truncation), extract iching for the card
      return { main: match[1].trim() + match[2].trim(), iching: match[2].trim() };
    }
  }
  return { main: text, iching: null };
}

/** Count Chinese characters in a string */
function countChinese(text: string): number {
  return (text.match(/[\u4e00-\u9fff\u3400-\u4dbf]/g) || []).length;
}

/** Detect if address is in a Portuguese-speaking country */
const PT_COUNTRY_PATTERN = /portugal|brasil|brazil|moçambique|mozambique|angola|cabo verde|são tomé|timor|macau|barreiro|lisboa|porto|faro|coimbra|braga|almada|amadora|setúbal|funchal|aveiro|leiria|évora|beja|guarda|viseu|bragança|santarém|cascais|sintra|oeiras|loures|seixal|gondomar|guimarães|odivelas|matosinhos|vila nova de gaia/i;

/** Export for reuse in Restaurants.tsx dialog */
export function getBuildingStoryParts(restaurant: {
  photo_story_zh?: string | null;
  photo_story_en?: string | null;
  photo_story_pt?: string | null;
  address?: string | null;
}, userLang?: string) {
  // photo_story_zh stores the native language of the restaurant's country
  // (e.g., French for Paris, Chinese for Beijing, Georgian for Tbilisi)
  // For PT-speaking countries, prefer photo_story_pt as the native source
  const isPt = PT_COUNTRY_PATTERN.test(restaurant.address || "");
  
  // Build prioritized list based on user's UI language first, then location native
  let storyPriority: (string | null | undefined)[];
  if (userLang === "pt") {
    storyPriority = [restaurant.photo_story_pt, restaurant.photo_story_en, restaurant.photo_story_zh];
  } else if (userLang === "en") {
    storyPriority = [restaurant.photo_story_en, restaurant.photo_story_pt, restaurant.photo_story_zh];
  } else if (userLang === "zh") {
    storyPriority = [restaurant.photo_story_zh, restaurant.photo_story_en, restaurant.photo_story_pt];
  } else if (isPt) {
    storyPriority = [restaurant.photo_story_pt, restaurant.photo_story_zh, restaurant.photo_story_en];
  } else {
    storyPriority = [restaurant.photo_story_zh, restaurant.photo_story_en, restaurant.photo_story_pt];
  }
  
  const nativeStory = storyPriority.find(s => !!s) || null;

  // For building narrative, use the prioritized story (without I Ching part)
  const { main: buildingNarrative } = nativeStory ? splitStory(nativeStory) : { main: "" };

  // For I Ching: find the version with the most Chinese characters
  // IChingSection will auto-translate non-Chinese content to Chinese
  const allStories = [
    restaurant.photo_story_zh,
    restaurant.photo_story_en,
    restaurant.photo_story_pt,
  ].filter(Boolean) as string[];

  let bestIChing: string | null = null;
  let bestChineseCount = 0;

  for (const story of allStories) {
    const { iching } = splitStory(story);
    if (iching) {
      const chCount = countChinese(iching);
      if (chCount > bestChineseCount) {
        bestChineseCount = chCount;
        bestIChing = iching;
      } else if (!bestIChing) {
        bestIChing = iching;
      }
    }
  }

  return { buildingNarrative, iChingFull: bestIChing };
}

/** Get a short preview snippet from building story (for list cards) */
export function getBuildingStorySnippet(restaurant: {
  photo_story_zh?: string | null;
  photo_story_en?: string | null;
  photo_story_pt?: string | null;
  address?: string | null;
}, maxLength = 60): string | null {
  const { buildingNarrative } = getBuildingStoryParts(restaurant);
  if (!buildingNarrative) return null;
  const clean = buildingNarrative.replace(/\n/g, ' ').trim();
  if (clean.length <= maxLength) return clean;
  return clean.substring(0, maxLength).replace(/\s+\S*$/, '') + '…';
}


interface BuildingStorySectionProps {
  restaurant: {
    id?: string;
    photo_story_zh?: string | null;
    photo_story_en?: string | null;
    photo_story_pt?: string | null;
    address?: string | null;
  };
  variant?: "section" | "card";
  /** External translated narrative (from parent unified translate) */
  narrativeOverride?: string | null;
  /** External translated I Ching (from parent unified translate) */
  iChingOverride?: string | null;
  /** Callback for translate button click inside card */
  onTranslateClick?: () => void;
  /** Whether translation is in progress */
  isTranslating?: boolean;
  /** Whether translated content is currently shown */
  showTranslation?: boolean;
}

export const BuildingStorySection = ({ restaurant, variant = "section", narrativeOverride, iChingOverride, onTranslateClick, isTranslating, showTranslation }: BuildingStorySectionProps) => {
  const { i18n, t } = useTranslation();
  const isMobile = useIsMobile();
  const { user } = useAuth();
  const [isExpanded, setIsExpanded] = useState(false);
  const [needsCollapse, setNeedsCollapse] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);
  const { counts, userReaction, toggleReaction } = useStoryReactions(restaurant.id);
  const { data: storyComments } = useComments(restaurant.id || "", "story", { enabled: !!restaurant.id });
  const [showComments, setShowComments] = useState(false);
  const commentsCount = storyComments?.reduce((acc, c) => acc + 1 + (c.replies?.length || 0), 0) || 0;
  const { share: smartShareFn, DrawerComponent: ShareDrawerComponent } = useSmartShare();

  const { buildingNarrative, iChingFull } = useMemo(
    () => getBuildingStoryParts(restaurant, i18n.language),
    [restaurant.photo_story_zh, restaurant.photo_story_en, restaurant.photo_story_pt, restaurant.address, i18n.language]
  );

  const hasContent = !!(buildingNarrative || iChingFull);
  
  // Check if content overflows the collapsed height
  const COLLAPSED_HEIGHT = isMobile ? 120 : 200;
  
  useEffect(() => {
    if (contentRef.current && variant === "card") {
      const height = contentRef.current.scrollHeight;
      setNeedsCollapse(height > COLLAPSED_HEIGHT + 40);
    }
  }, [buildingNarrative, iChingFull, narrativeOverride, iChingOverride, COLLAPSED_HEIGHT, variant]);
  
  // No longer need hideTranslateButton - translate is handled by parent

  if (!hasContent) return null;

  const sectionTitle = t("buildingStory.title", "Story");

  const handleReaction = (type: "like" | "dislike") => {
    if (!user) {
      toast.info(t("common.loginRequired", "请先登录"));
      return;
    }
    toggleReaction.mutate(type);
  };

  const handleShare = () => {
    smartShareFn({
      title: sectionTitle,
      url: window.location.href,
    });
  };

  const reactionButtons = (
    <div className="flex items-center justify-center gap-4 mt-4 pt-4 border-t border-border/50">
      <button
        onClick={() => handleReaction("like")}
        className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
          userReaction === "like"
            ? "bg-primary/15 text-primary"
            : "text-muted-foreground hover:text-primary hover:bg-primary/10"
        }`}
      >
        <ThumbsUp className={`w-4 h-4 ${userReaction === "like" ? "fill-primary" : ""}`} />
        <span>{counts.likes}</span>
      </button>
      <button
        onClick={() => handleReaction("dislike")}
        className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
          userReaction === "dislike"
            ? "bg-destructive/15 text-destructive"
            : "text-muted-foreground hover:text-destructive hover:bg-destructive/10"
        }`}
      >
        <ThumbsDown className={`w-4 h-4 ${userReaction === "dislike" ? "fill-destructive" : ""}`} />
        <span>{counts.dislikes}</span>
      </button>
      <button
        onClick={handleShare}
        className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 active:scale-95"
      >
        <Share2 className="w-4 h-4" />
      </button>
      <button
        onClick={() => setShowComments(!showComments)}
        className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
          showComments ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
        }`}
      >
        <MessageSquare className="w-4 h-4" />
        {commentsCount > 0 && <span>{commentsCount}</span>}
      </button>
    </div>
  );

  // Shared content block
  const storyContent = (
    <div className="relative">
      <div
        ref={contentRef}
        className="transition-all duration-300 ease-in-out overflow-hidden"
        style={
          variant === "card" && needsCollapse && !isExpanded
            ? { maxHeight: `${COLLAPSED_HEIGHT}px` }
            : { maxHeight: "none" }
        }
      >
        {buildingNarrative && (
          <p className="whitespace-pre-line text-sm leading-[1.8] text-foreground/90">
            {narrativeOverride || buildingNarrative}
          </p>
        )}
        {iChingFull && (
          <div className="mt-3 pt-3 border-t border-border/50">
            <IChingSection text={iChingFull} translatedText={iChingOverride} />
            {onTranslateClick && (
              <div className="flex justify-end mt-2">
                <button
                  className={`inline-flex items-center gap-1 min-h-[32px] py-1 px-2 rounded-md text-xs font-medium transition-all duration-200 active:scale-95 ${
                    isTranslating 
                      ? "text-muted-foreground cursor-wait" 
                      : showTranslation 
                        ? "text-primary bg-primary/10" 
                        : "text-muted-foreground hover:text-primary active:text-primary"
                  }`}
                  disabled={isTranslating}
                  onClick={onTranslateClick}
                >
                  {isTranslating ? (
                    <Loader2 className="h-3.5 w-3.5 animate-spin" />
                  ) : showTranslation ? (
                    <RotateCcw className="h-3.5 w-3.5" />
                  ) : (
                    <Languages className="h-3.5 w-3.5" />
                  )}
                  <span>
                    {isTranslating 
                      ? t("translate.translating", "翻译中...") 
                      : showTranslation 
                        ? t("translate.showOriginal", "显示原文") 
                        : t("translate.button", "翻译")}
                  </span>
                </button>
              </div>
            )}
          </div>
        )}
      </div>
      {/* Gradient fade + expand button */}
      {variant === "card" && needsCollapse && !isExpanded && (
        <div className="absolute bottom-0 left-0 right-0">
          <div className="h-12 bg-gradient-to-t from-background to-transparent" />
          <button
            onClick={() => setIsExpanded(true)}
            className="w-full flex items-center justify-center gap-1 py-1.5 text-xs text-primary hover:text-primary/80 font-medium transition-colors bg-background"
          >
            {t("buildingStory.readMore", "展开阅读")}
            <ChevronDown className="w-3.5 h-3.5" />
          </button>
        </div>
      )}
      {variant === "card" && needsCollapse && isExpanded && (
        <button
          onClick={() => setIsExpanded(false)}
          className="w-full flex items-center justify-center gap-1 py-1.5 mt-2 text-xs text-muted-foreground hover:text-foreground font-medium transition-colors"
        >
          {t("buildingStory.collapse", "收起")}
          <ChevronDown className="w-3.5 h-3.5 rotate-180" />
        </button>
      )}
      {/* Like/Dislike buttons */}
      {restaurant.id && reactionButtons}
      {/* Story Comments */}
      {restaurant.id && showComments && (
        <div className="mt-4 pt-4 border-t border-border/50">
          <RestaurantComments targetId={restaurant.id} targetType="story" />
        </div>
      )}
    </div>
  );

  if (variant === "card") {
    return (
      <>
        <div className="rounded-xl overflow-hidden border border-border/60 bg-gradient-to-b from-muted/30 to-background">
          {/* Compact card header */}
          <div className="flex items-center gap-2 px-3.5 py-2.5 border-b border-border/40 bg-gradient-to-r from-primary/8 to-transparent">
            <div className="flex items-center justify-center w-6 h-6 rounded-md bg-primary/12">
              <Landmark className="w-3.5 h-3.5 text-primary" />
            </div>
            <h3 className="text-xs font-semibold text-foreground">{sectionTitle}</h3>
            {(counts.likes > 0 || counts.dislikes > 0) && (
              <span className="inline-flex items-center gap-1.5 text-[10px] text-muted-foreground">
                <ThumbsUp className="w-3 h-3" />{counts.likes}
                <ThumbsDown className="w-3 h-3 ml-1" />{counts.dislikes}
              </span>
            )}
            <span className="text-[10px] text-muted-foreground ml-auto">
              {t("buildingStory.subtitle", "Restaurant · Building · Neighborhood")}
            </span>
          </div>
          <div className="px-3.5 py-3">
            {storyContent}
          </div>
        </div>
        {ShareDrawerComponent}
      </>
    );
  }

  return (
    <>
      <section className="py-8 md:py-12 lg:py-16">
        <div className="container mx-auto max-w-4xl px-4">
          <div className="text-center mb-6 md:mb-8 lg:mb-10">
            <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] md:tracking-[0.25em] uppercase text-primary mb-2 md:mb-3">
              {t("buildingStory.subtitle", "Restaurant · Building · Neighborhood")}
            </p>
            <h2 className="text-xl md:text-2xl lg:text-3xl font-bold text-foreground flex items-center justify-center gap-2 md:gap-3">
              <Landmark className="w-5 h-5 md:w-6 md:h-6 lg:w-7 lg:h-7 text-primary" />
              {sectionTitle}
              {(counts.likes > 0 || counts.dislikes > 0) && (
                <span className="inline-flex items-center gap-1.5 text-sm font-normal text-muted-foreground ml-1">
                  <ThumbsUp className="w-4 h-4" />{counts.likes}
                  <ThumbsDown className="w-4 h-4 ml-1" />{counts.dislikes}
                </span>
              )}
            </h2>
            <div className="w-12 md:w-16 h-0.5 md:h-1 bg-primary mx-auto mt-3 md:mt-4" />
          </div>

          <div className="rounded-xl overflow-hidden shadow-lg md:shadow-xl border border-border/50">
            <div className="relative bg-gradient-to-br from-primary/90 via-primary-light/80 to-accent/85 px-6 py-4">
              <div
                className="absolute inset-0 opacity-[0.06]"
                style={{
                  backgroundImage:
                    'url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.4\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")',
                }}
              />
              <div className="relative z-10 flex items-center gap-2">
                <span className="text-xl">🏛️</span>
                <span className="text-sm md:text-base font-medium text-primary-foreground/80">
                  {t("buildingStory.tagline", "We don't just document a restaurant — we document the story of a place")}
                </span>
              </div>
            </div>

            <div className="px-6 py-5 md:py-6 bg-background">
              {storyContent}
            </div>
          </div>
        </div>
      </section>
      {ShareDrawerComponent}
    </>
  );
};

export default BuildingStorySection;
